class TokenEmbedder:
    def __init__(self):
        self.bigram_to_idx = {}
        for i in range(26):
            for j in range(26):
                bg = chr(ord('a') + i) + chr(ord('a') + j)
                self.bigram_to_idx[bg] = i * 26 + j
        self.dim = 676

    def bigram_vector(self, token):
        vec = [0.0] * self.dim
        t = token.lower()
        for i in range(len(t) - 1):
            if 'a' <= t[i] <= 'z' and 'a' <= t[i+1] <= 'z':
                vec[self.bigram_to_idx[t[i] + t[i+1]]] += 1.0
        return vec

    def encode(self, text):
        return [self.bigram_vector(w) for w in text.lower().split()]

    def dot(self, a, b):
        return sum(x * y for x, y in zip(a, b))

    def maxsim(self, q_vecs, d_vecs):
        total = 0.0
        for qv in q_vecs:
            best = max(self.dot(qv, dv) for dv in d_vecs) if d_vecs else 0.0
            total += best
        return total

